                        card.id = `sm-card-${i}`;
                        card.className = 'relative rounded-xl overflow-hidden bg-gradient-to-br from-pink-50 to-purple-50 border-2 border-pink-200 flex items-center justify-center aspect-square';
                        card.innerHTML = '<div class="animate-spin rounded-full h-10 w-10 border-b-2 border-pink-600"></div>';
