                const btn = e.target.closest('button[data-count]');
                if (!btn) return;
                birthdayCountSel.querySelectorAll('button').forEach(b => b.classList.remove('selected'));
                btn.classList.add('selected');
                selectedCount = parseInt(btn.dataset.count, 10);
