        async function handleSkincareProductFiles(files) {
            if (files.length === 0) return;

            skincareImageUploadArea.classList.add('hidden');
            skincareImagePreviewContainer.classList.remove('hidden');

            let filesToProcess = files.length;

            for (const file of Array.from(files)) {
                let processedFile = file;

                // Convert HEIC to JPEG if needed
                if (file.type === 'image/heic' || file.name.toLowerCase().endsWith('.heic')) {
                    try {
                        processedFile = await convertHeicToJpeg(file);
                    } catch (err) {
                        console.error('HEIC conversion error:', err);
                        alert('Gagal mengkonversi file HEIC: ' + file.name);
                        filesToProcess--;
                        continue;
                    }
                }

                const reader = new FileReader();
                reader.onload = (e) => {
                    const parts = e.target.result.split(',');
                    const mimeType = parts[0].match(/:(.*?);/)[1];
                    const base64 = parts[1];
                    const imageData = { base64, mimeType, id: Date.now() + Math.random() };
                    skincareProductImages.push(imageData);

                    const previewWrapper = document.createElement('div');
                    previewWrapper.className = 'relative group';
                    previewWrapper.innerHTML = `
                        <img src="${e.target.result}" alt="Pratinjau Produk" class="rounded-lg w-full h-24 object-cover">
                        <button data-id="${imageData.id}" class="absolute top-1 right-1 bg-red-500 text-white rounded-full p-1 opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity focus:opacity-100">
                            <svg xmlns="http://www.w3.org/2000/svg" class="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M6 18L18 6M6 6l12 12"></path></svg>
                        </button>
                    `;

                    skincareImagePreviewContainer.appendChild(previewWrapper);

                    previewWrapper.querySelector('button').addEventListener('click', (btnEvent) => {
                        const idToRemove = parseFloat(btnEvent.currentTarget.getAttribute('data-id'));
                        skincareProductImages = skincareProductImages.filter(img => img.id !== idToRemove);
                        previewWrapper.remove();
                        if (skincareProductImages.length === 0) {
                            skincareImageUploadArea.classList.remove('hidden');
                            skincareImagePreviewContainer.classList.add('hidden');
                            const addButton = document.getElementById('skincare-add-more-button');
                            if (addButton) addButton.remove();
                        }
                        updateSkincareButtonState();
                    });

                    updateSkincareButtonState();

                    filesToProcess--;
                    if (filesToProcess === 0) {
                        manageSkincareAddMoreButton();
                    }
                };
                reader.readAsDataURL(processedFile);
            }
        }

        async function setupSkincareSingleImageUpload(input, uploadArea, previewContainer, previewImg, removeBtn, onUpload) {
            input.addEventListener('change', async (event) => {
                const file = event.target.files[0];
                if (file) {
                    let processedFile = file;

                    // Convert HEIC to JPEG if needed
                    if (file.type === 'image/heic' || file.name.toLowerCase().endsWith('.heic')) {
                        try {
                            processedFile = await convertHeicToJpeg(file);
                        } catch (err) {
                            console.error('HEIC conversion error:', err);
                            alert('Gagal mengkonversi file HEIC');
                            return;
                        }
                    }

                    const reader = new FileReader();
                    reader.onload = (e) => {
                        previewImg.src = e.target.result;
                        const parts = e.target.result.split(',');
                        const mimeType = parts[0].match(/:(.*?);/)[1];
                        const base64 = parts[1];
                        onUpload(base64, mimeType);

                        uploadArea.classList.add('hidden');
                        previewContainer.classList.remove('hidden');
                    };
                    reader.readAsDataURL(processedFile);
                }
            });

            removeBtn.addEventListener('click', () => {
                onUpload(null, null);
                input.value = '';
                uploadArea.classList.remove('hidden');
                previewContainer.classList.add('hidden');
            });
        }

