    // ==================== PHOTO BOOTH ====================
    (function() {
        const apiKey = "";

        // Element references
        const photoBoothInput = document.getElementById('photo-booth-input');
        const photoBoothUploadBox = document.getElementById('photo-booth-upload-box');
        const photoBoothPlaceholder = document.getElementById('photo-booth-placeholder');
        const photoBoothPreviewContainer = document.getElementById('photo-booth-preview-container');
        const photoBoothGenerateBtn = document.getElementById('photo-booth-generate-btn');
        const photoBoothFrameOptions = document.getElementById('photo-booth-frame-options');
        const photoBoothCustomThemeContainer = document.getElementById('photo-booth-custom-theme-container');
        const photoBoothCustomThemeInput = document.getElementById('photo-booth-custom-theme-input');
        const photoBoothRatioOptions = document.getElementById('photo-booth-ratio-options');
        const photoBoothResultsPlaceholder = document.getElementById('photo-booth-results-placeholder');
        const photoBoothResultsContainer = document.getElementById('photo-booth-results-container');
        const photoBoothResultsGrid = document.getElementById('photo-booth-results-grid');
        const photoBoothDownloadAllBtn = document.getElementById('photo-booth-download-all-btn');

        if (!photoBoothInput) return;

        let uploadedImages = []; // Array of multiple photos
        let generatedImages = [];
        let selectedFrame = 'Classic Strip';
        let selectedRatio = '3:4';
        let selectedCount = 4; // 1-10, default 4 (count selector)

        // Count selection (1-10), default 4
        const photoBoothCountSel = document.getElementById('photo-booth-count-selection-grid');
        if (photoBoothCountSel) {
            photoBoothCountSel.addEventListener('click', (e) => {
                const btn = e.target.closest('button[data-count]');
                if (!btn) return;
                photoBoothCountSel.querySelectorAll('button').forEach(b => b.classList.remove('selected'));
                btn.classList.add('selected');
                selectedCount = parseInt(btn.dataset.count, 10);
            });
        }

        // Setup multiple image upload with HEIC support
        photoBoothInput.addEventListener('change', async (e) => {
            const files = Array.from(e.target.files);
            if (files.length === 0) return;

            // Limit to max 4 photos
            const filesToProcess = files.slice(0, 4);

            photoBoothPlaceholder.classList.add('hidden');
            photoBoothPreviewContainer.classList.remove('hidden');
            photoBoothPreviewContainer.innerHTML = ''; // Clear existing previews
            uploadedImages = []; // Reset

            for (const file of filesToProcess) {
                try {
                    let processedFile = file;

                    // Convert HEIC to JPEG if necessary
                    if (file.type === 'image/heic' || file.name.toLowerCase().endsWith('.heic')) {
                        const heic2any = window.heic2any;
                        if (heic2any) {
                            const convertedBlob = await heic2any({ blob: file, toType: 'image/jpeg', quality: 0.9 });
                            processedFile = new File([convertedBlob], file.name.replace(/\.heic$/i, '.jpg'), { type: 'image/jpeg' });
                        }
                    }

                    const reader = new FileReader();
                    reader.onload = (event) => {
                        const dataUrl = event.target.result;
                        const base64 = dataUrl.split(',')[1];

                        uploadedImages.push({
                            base64: base64,
                            mimeType: processedFile.type,
                            dataUrl: dataUrl
                        });

                        // Create preview item (mobile-friendly)
                        const previewItem = document.createElement('div');
                        previewItem.className = 'photo-booth-preview-item relative';
                        previewItem.innerHTML = `
                            <img src="${dataUrl}" class="w-full h-24 object-cover rounded-lg shadow-md" alt="Preview">
                            <button type="button" class="remove-photo-btn absolute -top-2 -right-2 bg-red-600 text-white rounded-full w-6 h-6 flex items-center justify-center hover:bg-red-700 shadow-lg text-xs opacity-0 transition-opacity" data-index="${uploadedImages.length - 1}">
                                <i class="fas fa-times"></i>
                            </button>
                        `;
                        photoBoothPreviewContainer.appendChild(previewItem);

                        // Enable generate button
                        photoBoothGenerateBtn.disabled = false;
                    };
                    reader.readAsDataURL(processedFile);
                } catch (error) {
                    console.error('Error processing image:', error);
                }
            }
        });

        // Remove individual photo handler (event delegation)
        photoBoothPreviewContainer.addEventListener('click', (e) => {
            const removeBtn = e.target.closest('.remove-photo-btn');
            if (!removeBtn) return;

            const index = parseInt(removeBtn.dataset.index);
            uploadedImages.splice(index, 1);

            // Re-render previews
            photoBoothPreviewContainer.innerHTML = '';
            uploadedImages.forEach((img, i) => {
                const previewItem = document.createElement('div');
                previewItem.className = 'relative group';
                previewItem.innerHTML = `
                    <img src="${img.dataUrl}" class="w-full h-24 object-cover rounded-lg shadow-md" alt="Preview">
                    <button type="button" class="remove-photo-btn absolute -top-2 -right-2 bg-red-600 text-white rounded-full w-6 h-6 flex items-center justify-center hover:bg-red-700 shadow-lg text-xs opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity" data-index="${i}">
                        <i class="fas fa-times"></i>
                    </button>
                `;
                photoBoothPreviewContainer.appendChild(previewItem);
            });

            // If no photos left, show placeholder and disable button
            if (uploadedImages.length === 0) {
                photoBoothPlaceholder.classList.remove('hidden');
                photoBoothPreviewContainer.classList.add('hidden');
                photoBoothGenerateBtn.disabled = true;
                photoBoothInput.value = '';

                // Reset results
                photoBoothResultsPlaceholder.classList.remove('hidden');
                photoBoothResultsContainer.classList.add('hidden');
                photoBoothResultsGrid.innerHTML = '';
                generatedImages = [];
            }
        });

        // Frame theme selection handler
        photoBoothFrameOptions.addEventListener('click', (e) => {
            const button = e.target.closest('button');
            if (!button) return;

            photoBoothFrameOptions.querySelectorAll('button').forEach(btn => btn.classList.remove('selected'));
            button.classList.add('selected');
            selectedFrame = button.dataset.value;

            // Show/hide custom theme input
            if (selectedFrame === 'Custom') {
                photoBoothCustomThemeContainer.classList.remove('hidden');
            } else {
                photoBoothCustomThemeContainer.classList.add('hidden');
            }
        });

        // Aspect ratio selection handler
        photoBoothRatioOptions.addEventListener('click', (e) => {
            const button = e.target.closest('button');
            if (!button) return;

            photoBoothRatioOptions.querySelectorAll('button').forEach(btn => btn.classList.remove('selected'));
            button.classList.add('selected');
            selectedRatio = button.dataset.value;
        });

        // Generate button handler
        photoBoothGenerateBtn.addEventListener('click', async () => {
            if (uploadedImages.length === 0) {
                alert('Silakan unggah foto terlebih dahulu');
                return;
            }

            // Determine frame theme
            let frameTheme = selectedFrame;
            if (selectedFrame === 'Custom' && photoBoothCustomThemeInput) {
                const customTheme = photoBoothCustomThemeInput.value.trim();
                frameTheme = customTheme || 'Classic Strip';
            }

            // Create prompt based on frame theme with ALL themes
            const frameDescriptions = {
                'Classic Strip': 'classic black and white photo booth strip style with film-like borders, vintage camera aesthetic, fun and nostalgic feel, multiple photo frames arranged vertically',
                'Foto Box': 'foto box style with multiple photo frames in a grid layout (2x2 or similar), clean borders between photos, professional photo booth aesthetic, perfect for group photos or multiple moments',
                'Vintage Polaroid': 'vintage polaroid instant photo style with white borders, retro 70s aesthetic, warm nostalgic colors, instant camera feel',
                'Colorful Party': 'vibrant colorful party photo booth style with confetti, balloons, festive decorations, fun celebration vibes, energetic atmosphere',
                'Wedding Elegant': 'elegant wedding photo booth style with romantic decorative frames, soft lighting, flowers and elegant patterns, sophisticated and classy',
                'Birthday Fun': 'fun birthday party photo booth with birthday cake, balloons, presents, cheerful decorations, festive celebration theme',
                'Retro 80s': 'retro 1980s style photo booth with neon colors, geometric patterns, vibrant pink and blue tones, nostalgic 80s aesthetic, vintage vibes',
                'Modern Minimal': 'modern minimalist photo booth style with clean lines, simple elegant frames, contemporary aesthetic, sleek design',
                'Neon Cyberpunk': 'neon cyberpunk futuristic photo booth with glowing neon lights, electric blue and pink colors, sci-fi aesthetic, digital futuristic vibe',
                'Tropical Beach': 'tropical beach photo booth theme with palm trees, ocean background, sunny vibes, summer vacation aesthetic, relaxed and breezy',
                'Christmas Holiday': 'Christmas holiday photo booth with snowflakes, santa hats, christmas trees, festive red and green colors, winter wonderland theme',
                'Halloween Spooky': 'Halloween spooky photo booth with pumpkins, ghosts, bats, orange and black colors, fun scary atmosphere, trick or treat vibes',
                'Valentine Love': 'Valentine romantic photo booth with hearts, roses, pink and red colors, love theme, romantic and sweet atmosphere',
                'Graduation': 'graduation ceremony photo booth with cap and gown, diplomas, academic achievement theme, proud and celebratory atmosphere',
                'Baby Shower': 'baby shower photo booth with cute baby decorations, pastel colors, teddy bears, baby bottles, adorable and sweet theme',
                'Festival Concert': 'music festival concert photo booth with stage lights, musical instruments, energetic crowd vibes, rock and roll aesthetic',
                'Movie Cinema': 'movie cinema photo booth with film reels, popcorn, movie tickets, Hollywood glamour, red carpet aesthetic',
                'Travel Adventure': 'travel adventure photo booth with landmarks, suitcases, passports, wanderlust theme, explorer vibes, world traveler aesthetic',
                'Anime Manga': 'anime manga style photo booth with Japanese pop culture elements, vibrant colors, comic book style frames, otaku aesthetic',
                'Gaming Esports': 'gaming esports photo booth with controllers, digital effects, neon gaming lights, competitive gamer aesthetic, tech-savvy theme',
                'Sports Team': 'sports team photo booth with trophies, medals, team colors, athletic energy, champion celebration theme',
                'Korean Photobox': 'korean photobox studio inside a small corner room with 3 walls visible, fisheye lens with barrel distortion effect, ultra wide 0.5 iPhone camera style angle, top down slightly, CCTV aesthetic, plain solid wall colors (light grey, beige, light brown), minimal studio with no busy decorations, tight corner box feel, softbox lighting with diffused light, evenly lit face and body, casual candid poses with peace signs and fun expressions, friends having fun, standing close to camera, full body shot visible, high detail DSLR photography, korean photo booth aesthetic'
            };

            const frameDescription = frameDescriptions[selectedFrame] || frameTheme;

            // Build prompt based on number of uploaded photos
            let photoInstruction = '';
            if (uploadedImages.length === 1) {
                photoInstruction = 'Keep the person\'s face and identity EXACTLY the same as in the uploaded photo';
            } else {
                photoInstruction = `Include ALL ${uploadedImages.length} people from the uploaded photos in the photo booth image. Each person should be clearly visible and their identities preserved. ${selectedFrame === 'Foto Box' ? 'Arrange them in a grid layout with separate frames for each person or group them naturally in one frame' : 'Group them together naturally in the frame'}`;
            }

            const prompt = `Create a professional photo booth image featuring ${uploadedImages.length === 1 ? 'the person' : `all ${uploadedImages.length} people`} from the uploaded ${uploadedImages.length === 1 ? 'photo' : 'photos'}.

FRAME STYLE: Apply a ${frameDescription} theme with decorative frame borders and aesthetic effects.

IMPORTANT REQUIREMENTS:
- ${photoInstruction}
- Create natural, fun, and engaging photo booth poses and expressions
- Add appropriate decorative frame borders that match the ${frameTheme} theme
- Include subtle effects like lighting, filters, or overlays that enhance the photo booth aesthetic
- Make it look like a real photo booth picture with authentic styling
- Ensure high quality and professional appearance
- ${uploadedImages.length > 1 ? 'Make sure all people are clearly visible and well-composed in the frame' : 'Focus on the person with great composition'}

The final result should be a complete photo booth image ready to print or share, with ${uploadedImages.length === 1 ? 'the person' : 'all people'} clearly recognizable and the frame style prominently featured.`;

            await generatePhotoBoothSet(prompt);
        });

        async function generatePhotoBoothSet(prompt) {
            const originalBtnHTML = photoBoothGenerateBtn.innerHTML;
            photoBoothGenerateBtn.disabled = true;
            photoBoothGenerateBtn.innerHTML = '<i class="fas fa-spinner fa-spin mr-2"></i>Membuat Photo Booth...';

            photoBoothResultsPlaceholder.classList.add('hidden');
            photoBoothResultsContainer.classList.remove('hidden');

            let attempts = 0;
            const MAX_ATTEMPTS = 3;
            let successCount = 0;

            while (attempts < MAX_ATTEMPTS && successCount === 0) {
                attempts++;
                generatedImages = [];
                photoBoothResultsGrid.innerHTML = '';

                for (let i = 1; i <= selectedCount; i++) {
                    const card = document.createElement('div');
                    card.id = `photo-booth-card-${i}`;
                    card.className = 'relative group rounded-xl overflow-hidden bg-gray-100 flex items-center justify-center aspect-[3/4]';
                    card.innerHTML = '<div class="animate-spin rounded-full h-10 w-10 border-b-2 border-purple-600"></div>';
                    photoBoothResultsGrid.appendChild(card);
                }

                const generationPromises = Array.from({ length: selectedCount }, (_, i) =>
                    generateSinglePhotoBoothImage(i + 1, prompt)
                );
                await Promise.allSettled(generationPromises);

                photoBoothResultsGrid.querySelectorAll('[id^="photo-booth-card-"]').forEach(card => {
                    if (!card.querySelector('img')) card.remove();
                });
                successCount = generatedImages.filter(Boolean).length;
            }

            if (successCount === 0) {
                alert('Akun Google ini sudah mencapai batas, silahkan gunakan akun Google lain');
            }

            photoBoothGenerateBtn.disabled = false;
            photoBoothGenerateBtn.innerHTML = originalBtnHTML;
        }

        async function generateSinglePhotoBoothImage(index, basePrompt) {
            const card = document.getElementById(`photo-booth-card-${index}`);
            try {
                const apiUrl = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-image-preview:generateContent?key=${apiKey}`;

                const finalPrompt = `${basePrompt}\n\nThis is photo booth variation number ${index}. Make this variation unique with different pose, expression, or slight styling variations while maintaining the same frame theme and ${uploadedImages.length === 1 ? "person's identity" : "all people's identities"}.`;

                // Build parts array: prompt + all uploaded images
                const parts = [{ text: finalPrompt }];

                // Add all uploaded images to the request
                uploadedImages.forEach(img => {
                    parts.push({ inlineData: { mimeType: img.mimeType, data: img.base64 } });
                });

                const payload = {
                    contents: [{ parts: parts }],
                    generationConfig: {
                        responseModalities: ['TEXT', 'IMAGE'],
                        imageConfig: { aspectRatio: selectedRatio }
                    },
                    safetySettings: [
                        { category: 'HARM_CATEGORY_HARASSMENT', threshold: 'BLOCK_NONE' },
                        { category: 'HARM_CATEGORY_HATE_SPEECH', threshold: 'BLOCK_NONE' },
                        { category: 'HARM_CATEGORY_SEXUALLY_EXPLICIT', threshold: 'BLOCK_NONE' },
                        { category: 'HARM_CATEGORY_DANGEROUS_CONTENT', threshold: 'BLOCK_NONE' }
                    ]
                };

                const response = await fetch(apiUrl, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(payload)
                });
                const result = await response.json();
                const base64Data = result?.candidates?.[0]?.content?.parts?.find(p => p.inlineData)?.inlineData?.data;
                if (!base64Data) throw new Error('No image data received');

                const imageUrl = `data:image/png;base64,${base64Data}`;
                const filename = `photo_booth_${selectedFrame.replace(/\s+/g, '_')}_${Date.now()}_${index}.png`;
                generatedImages[index - 1] = { url: imageUrl, filename };

                card.className = 'relative group rounded-xl overflow-hidden shadow-lg hover:shadow-2xl transition-all duration-300';
                card.innerHTML = `
                    <img src="${imageUrl}" class="w-full h-full object-cover" alt="Photo Booth ${index}">
                    <div class="absolute inset-0 bg-gradient-to-t from-black/80 via-black/40 to-transparent opacity-100 sm:opacity-0 sm:group-hover:opacity-100 transition-opacity duration-300 flex items-end justify-center pb-4 gap-2">
                        <button data-action="preview" data-index="${index - 1}" class="action-btn bg-white/90 hover:bg-white text-gray-800 px-4 py-2 rounded-full font-semibold shadow-lg transition-all duration-200 hover:scale-105 flex items-center gap-2">
                            <i class="fas fa-eye"></i>
                            <span class="hidden sm:inline">Preview</span>
                        </button>
                        <button data-action="download" data-index="${index - 1}" class="action-btn bg-gradient-to-r from-purple-500 to-pink-500 hover:from-purple-600 hover:to-pink-600 text-white px-4 py-2 rounded-full font-semibold shadow-lg transition-all duration-200 hover:scale-105 flex items-center gap-2">
                            <i class="fas fa-download"></i>
                            <span class="hidden sm:inline">Download</span>
                        </button>
                    </div>
                `;
            } catch (error) {
                console.error(`Error generating photo booth ${index}:`, error);
                if (card) card.innerHTML = '';
            }
        }

        // Event delegation for action buttons
        photoBoothResultsGrid.addEventListener('click', async (e) => {
            e.stopPropagation();

            const actionBtn = e.target.classList.contains('action-btn') ? e.target : e.target.closest('.action-btn[data-action]');
            if (!actionBtn) return;

            const action = actionBtn.dataset.action;
            const index = parseInt(actionBtn.dataset.index, 10);
            const imageData = generatedImages[index];

            if (!imageData) return;

            if (action === 'preview') {
                if (window.showPreviewModal) {
                    window.showPreviewModal(imageData.url);
                }
            } else if (action === 'download') {
                if (window.downloadDataURINew) {
                    await window.downloadDataURINew(imageData.url, imageData.filename);
                } else if (window.downloadImage) {
                    await window.downloadImage(imageData.url, imageData.filename);
                }
            }
        });

        // Download all functionality
        if (photoBoothDownloadAllBtn) {
            photoBoothDownloadAllBtn.addEventListener('click', async () => {
                if (generatedImages.length === 0) return;

                photoBoothDownloadAllBtn.disabled = true;
                photoBoothDownloadAllBtn.innerHTML = '<i class="fas fa-spinner fa-spin mr-2"></i>Downloading...';

                for (let i = 0; i < generatedImages.length; i++) {
                    const img = generatedImages[i];
                    if (window.downloadImage) {
                        await window.downloadImage(img.url, img.filename);
                    } else if (window.downloadDataURINew) {
                        await window.downloadDataURINew(img.url, img.filename);
                    }
                    await new Promise(resolve => setTimeout(resolve, 500));
                }

                photoBoothDownloadAllBtn.disabled = false;
                photoBoothDownloadAllBtn.innerHTML = '<i class="fas fa-download mr-2"></i>Download Semua';
            });
        }
    })();

