                generateBtn.innerHTML = '<i class="fas fa-spinner fa-spin mr-2"></i>Generating...';

                if (emptyState) emptyState.classList.add('hidden');
                if (resultsSection) resultsSection.classList.remove('hidden');

                const MAX_ATTEMPTS = 3;
